"use client";

import { motion } from "framer-motion";

interface Section {
  heading: string;
  content: string;
}

interface Condition {
  slug: string;
  title: string;
  shortDescription: string;
  icon: string;
  sections: Section[];
}

interface ConditionDetailPanelProps {
  condition: Condition;
}

export function ConditionDetailPanel({ condition }: ConditionDetailPanelProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
    >
      {/* Header */}
      <div className="text-center mb-16">
        <span className="text-blue-400 font-medium tracking-wide text-sm mb-3 block">
          Condition
        </span>
        <h1 className="text-4xl md:text-5xl font-semibold text-foreground mb-6 tracking-tight">
          {condition.title}
        </h1>
        <p className="text-muted text-lg leading-relaxed max-w-2xl mx-auto">
          {condition.shortDescription}
        </p>
      </div>

      {/* Sections */}
      <div className="space-y-6 max-w-3xl mx-auto">
        {condition.sections.map((section, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: index * 0.1 }}
            className="glass-panel p-8 rounded-[2rem]"
          >
            <h2 className="text-xl font-semibold text-foreground mb-3">
              {section.heading}
            </h2>
            <p className="text-muted text-sm leading-relaxed">
              {section.content}
            </p>
          </motion.div>
        ))}
      </div>
    </motion.div>
  );
}
